#include <bits/stdc++.h>
using namespace std;

long long a, b, s[18], g[18], f[18][11][11], ff[18][11][11];
int t, n, i, j, k, p, z, c[18];

long long solve(long long x) {
    if (x < 100) return 0;

    long long r = 0;
    for (i = 0; x > 0; i++) {
        c[i] = x % 10;
        x /= 10;
    }

    n = i - 1;

    for (i = 0; i <= n; i++) r += g[i];

    for (i = 1; i < c[n]; i++) r += ff[n + 1][i][9];

    if (c[n - 1] > 0) r += ff[n + 1][c[n]][c[n - 1] - 1];

    for (i = n - 1, k = 0; i > 0; i--) {
        z = c[i - 1];
        p = 0;

        if (c[i] < c[i + 1] && z > c[i]) p = z - c[i] - 1;

        if (c[i] > c[i + 1]) {
            if (z < c[i]) p = z;
            else p = c[i];
        }

        r += (long long)(k * z + p) * s[i - 1];

        if (z > 0) r += ff[i + 1][c[i]][z - 1];

        if ((c[i] < c[i + 1] && c[i] < c[i - 1]) ||
            (c[i] > c[i - 1] && c[i] > c[i + 1])) k++;
    }

    return r + k;
}

int main() {

    s[0] = 1;
    for (i = 1; i < 18; i++) s[i] = s[i - 1] * 10;

    for (n = 3; n < 17; n++) {
        for (i = 0; i < 10; i++) {
            for (j = 0; j < 10; j++) {

                for (k = 0; k < 10; k++) {
                    f[n][i][j] += f[n - 1][j][k] +
                        (((i < j && k < j) || (i > j && k > j)) ? s[n - 3] : 0);
                }

                if (i > 0) g[n] += f[n][i][j];

                if (j == 0) ff[n][i][j] = f[n][i][j];
                else ff[n][i][j] = ff[n][i][j - 1] + f[n][i][j];
            }
        }
    }

    cin >> t;

    while (t--) {
        cin >> a >> b;
        cout << solve(b) - solve(a - 1) << "\n";
    }

    return 0;
}

