import java.io.*;
import java.util.*;

public class Main {

    static long a, b;
    static long[] s = new long[18];
    static long[] g = new long[18];
    static long[][][] f = new long[18][11][11];
    static long[][][] ff = new long[18][11][11];
    static int[] c = new int[18];

    static long solve(long x) {
        if (x < 100) return 0;

        long r = 0;
        int i = 0;

        while (x > 0) {
            c[i] = (int)(x % 10);
            x /= 10;
            i++;
        }

        int n = i - 1;

        for (i = 0; i <= n; i++) r += g[i];

        for (i = 1; i < c[n]; i++) r += ff[n + 1][i][9];

        if (c[n - 1] > 0) r += ff[n + 1][c[n]][c[n - 1] - 1];

        int k = 0;

        for (i = n - 1; i > 0; i--) {

            int z = c[i - 1];
            int p = 0;

            if (c[i] < c[i + 1] && z > c[i]) p = z - c[i] - 1;

            if (c[i] > c[i + 1]) {
                if (z < c[i]) p = z;
                else p = c[i];
            }

            r += (long)(k * z + p) * s[i - 1];

            if (z > 0) r += ff[i + 1][c[i]][z - 1];

            if ((c[i] < c[i + 1] && c[i] < c[i - 1]) ||
                (c[i] > c[i - 1] && c[i] > c[i + 1])) k++;
        }

        return r + k;
    }

    public static void main(String[] args) throws Exception {

        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;

        s[0] = 1;
        for (int i = 1; i < 18; i++) s[i] = s[i - 1] * 10;

        for (int n = 3; n < 17; n++) {
            for (int i = 0; i < 10; i++) {
                for (int j = 0; j < 10; j++) {

                    for (int k = 0; k < 10; k++) {
                        f[n][i][j] += f[n - 1][j][k]
                                + (((i < j && k < j) || (i > j && k > j)) ? s[n - 3] : 0);
                    }

                    if (i > 0) g[n] += f[n][i][j];

                    if (j == 0) ff[n][i][j] = f[n][i][j];
                    else ff[n][i][j] = ff[n][i][j - 1] + f[n][i][j];
                }
            }
        }

        int t = Integer.parseInt(br.readLine());

        while (t-- > 0) {
            st = new StringTokenizer(br.readLine());
            a = Long.parseLong(st.nextToken());
            b = Long.parseLong(st.nextToken());

            System.out.println(solve(b) - solve(a - 1));
        }
    }
}

